jQuery(document).on("ajaxSuccess",function(e,o,n){const t=new URLSearchParams(n.data);if("elementor_pro_forms_send_form"!==t.get("action"))return;const r=t.get("form_id"),c=jQuery('input[name="form_id"][value="'+r+'"]').closest("form");window.ProcaptchaReset(c[0])});const procaptchaElementorPro=function(){"undefined"!=typeof elementorFrontend&&elementorFrontend.hooks.addAction("frontend/element_ready/widget",function(e){e[0].classList.contains("elementor-widget-form")&&ProcaptchaBindEvents()})};window.ProcaptchaElementorPro=procaptchaElementorPro,jQuery(document).ready(procaptchaElementorPro);